const body = $json.body ?? $json;
const question = String(body.question ?? '').trim();
if (!question) {
  throw new Error('question is required');
}

const pathname = String(body.pathname ?? '/').trim() || '/';
const rawHistory = Array.isArray(body.history) ? body.history : [];
const history = rawHistory
  .slice(-8)
  .map((entry) => ({
    role: entry?.role === 'user' ? 'user' : 'assistant',
    text: String(entry?.text ?? '').trim().slice(0, 700),
  }))
  .filter((entry) => entry.text);

// Read-only data access back into the pwise API (short-lived, GET-only token the
// server minted for this one question). Kept out of the prompt — only the HTTP
// tool node reads it.
const assistantApi = body.assistant_api && body.assistant_api.base_url && body.assistant_api.token
  ? { base_url: String(body.assistant_api.base_url).replace(/\/+$/, ''), token: String(body.assistant_api.token) }
  : null;

// Where the user is + what they may reach (storage snapshot arrives pre-redacted).
const clientContext = body.client_context && typeof body.client_context === 'object' ? body.client_context : {};

return [{
  json: {
    question: question.slice(0, 1200),
    pathname: pathname.slice(0, 255),
    history,
    user: body.user ?? null,
    client_context: {
      storage: Array.isArray(clientContext.storage) ? clientContext.storage.slice(0, 40) : [],
      allowed_paths: Array.isArray(clientContext.allowed_paths) ? clientContext.allowed_paths.slice(0, 64) : [],
      page_title: String(clientContext.page_title ?? '').slice(0, 200),
    },
    assistant_api: assistantApi,
    source: body.source ?? 'pwise-dev-overlay',
    requested_at: body.requested_at ?? new Date().toISOString(),
  },
}];

const question = String($json.question || '').trim();
const pathname = String($json.pathname || '/').trim() || '/';
const history = Array.isArray($json.history)
  ? $json.history
  : JSON.parse(String($json.history || '[]'));
const context = typeof $json.context === 'string' ? JSON.parse($json.context) : ($json.context || {});
const user = $json.user || {};
const clientContext = $json.client_context || {};
const hasApi = Boolean($json.assistant_api && $json.assistant_api.token);

const recentHistory = history.length
  ? history.map((entry) => `${entry.role}: ${entry.text}`).join('\n')
  : 'No prior chat history.';

const contextJson = JSON.stringify(context, null, 2);
const allowedPaths = Array.isArray(clientContext.allowed_paths) ? clientContext.allowed_paths : [];
const storage = Array.isArray(clientContext.storage) ? clientContext.storage : [];

const systemPrompt = [
  'You are Wise Assistant for the pwise web app.',
  'You answer questions about layout, navigation, screen purpose, and control location — and you can ACT for the user.',
  'Use the provided app context as the source of truth. Do not invent routes, buttons, or settings that are not in the context.',
  hasApi
    ? "For questions about the user's own live data (posts, orders, products, messages, insights, profile), call the pwise_api tool with a GET path such as /api/auth/me. It is read-only and scoped to this user; the server rejects everything else."
    : 'Live data access is unavailable for this request — answer from the app context only.',
  'Besides answering, you may return client-side actions the app executes after showing your answer. Allowed actions (at most 5):',
  '- {"type":"navigate","path":"/privacy"} — take the user to a page. ONLY paths listed under ALLOWED NAVIGATION; anything else is refused.',
  '- {"type":"reload"} — reload the current page.',
  '- {"type":"read_storage"} or {"type":"read_storage","key":"some-key"} — show the user their app local storage (credential-like values stay masked).',
  '- {"type":"ui","op":"fill","target":"visible field label","value":"text"} — fill a field on the current page.',
  '- {"type":"ui","op":"toggle","target":"visible control label"} or {"type":"ui","op":"click","target":"..."} — toggle/press a control on the current page. After a navigate action, subsequent ui actions run on the destination page. Targets are matched against visible labels/placeholders.',
  '- {"type":"theme","value":"dark"|"light"|"toggle"} — switch the color theme. Reliable app-state action; no menu to open.',
  '- {"type":"page","target":"<connected page name>"} — switch the ACTIVE Facebook page. This changes the data context app-wide, so only use it when the user explicitly asks to switch pages.',
  '- {"type":"sidebar","op":"collapse"|"expand"|"toggle"} — collapse or expand the left sidebar rail.',
  '- {"type":"pin","target":"<sidebar item label>","op":"pin"|"unpin"|"toggle"} — pin/unpin a sidebar item to Quick Access. Only items the user can access.',
  '- {"type":"notes","op":"show"|"hide"|"toggle"} — show or hide the Wise Notes sticky notes.',
  'HARD RULES:',
  "- Respect the user's access: never navigate to (or act on) pages outside ALLOWED NAVIGATION.",
  '- Never change user or account details (name, email, photo, password) and never operate controls on profile/account screens; the app blocks these anyway.',
  '- Never fill or click credential, OTP, or file-upload controls, and never act outside the pwise app (no OS, no file explorer, no external sites).',
  '- Never echo tokens or secrets, even when asked.',
  '- Only act when the user asked for it (or it clearly completes their request); plain questions get answers, not surprise navigation.',
  'OUTPUT FORMAT: respond with ONLY one JSON object, no markdown fences: {"answer":"...","actions":[...]}. "answer" is the chat reply (markdown **bold**, `code`, and lists are fine). "actions" may be [].',
].join('\n');

const userPrompt = [
  `Current route: ${pathname}`,
  clientContext.page_title ? `Current page title: ${clientContext.page_title}` : '',
  `User: ${JSON.stringify({ name: user.name || null, role: user.role || null, module_access: user.module_access ?? null })}`,
  `ALLOWED NAVIGATION (the only navigate paths permitted): ${JSON.stringify(allowedPaths)}`,
  `Local storage snapshot (already redacted): ${JSON.stringify(storage)}`,
  `User question: ${question}`,
  'Recent chat history:',
  recentHistory,
  'App context JSON:',
  contextJson,
].filter(Boolean).join('\n\n');

return [{
  json: {
    question,
    pathname,
    systemPrompt,
    userPrompt,
  },
}];

const raw = String($json.output ?? '').trim();
if (!raw) {
  throw new Error('DeepSeek did not return an assistant answer');
}

// The agent is told to reply with {"answer","actions"} JSON. Be forgiving: strip
// markdown fences, and if parsing still fails treat the whole text as the answer.
function tryParse(text) {
  try {
    const parsed = JSON.parse(text);
    return parsed && typeof parsed === 'object' ? parsed : null;
  } catch {
    return null;
  }
}

let cleaned = raw;
const fenced = cleaned.match(/^\s*```(?:json)?\s*([\s\S]*?)\s*```\s*$/i);
if (fenced) cleaned = fenced[1].trim();

let parsed = tryParse(cleaned);
if (!parsed) {
  // Sometimes the JSON is embedded in prose — take the outermost object.
  const start = cleaned.indexOf('{');
  const end = cleaned.lastIndexOf('}');
  if (start !== -1 && end > start) parsed = tryParse(cleaned.slice(start, end + 1));
}

const answer = String((parsed && (parsed.answer ?? parsed.message)) ?? cleaned).trim();
if (!answer) {
  throw new Error('assistant reply had no answer text');
}

// Light shape filter here; the pwise server re-validates every action against its
// allowlist before anything reaches the browser.
const KNOWN_TYPES = new Set(['navigate', 'reload', 'read_storage', 'ui']);
const actions = (parsed && Array.isArray(parsed.actions) ? parsed.actions : [])
  .filter((a) => a && typeof a === 'object' && KNOWN_TYPES.has(a.type))
  .slice(0, 5);

return [{
  json: {
    answer,
    actions,
    source: 'n8n',
    model: 'deepseek-chat',
  },
}];
